import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void dashesStripped() {
        assertTrue(new Solution().isPalindromicAccountNumber("40-04"));
    }

    @Test
    void spacesStripped() {
        assertTrue(new Solution().isPalindromicAccountNumber("1 2 3 2 1"));
    }

    @Test
    void mixedSeparators() {
        // "12-3-21" strips to "12321" → palindrome
        assertTrue(new Solution().isPalindromicAccountNumber("12-3-21"));
    }

    @Test
    void alphanumericIgnoreCase() {
        assertTrue(new Solution().isPalindromicAccountNumber("A1-1-A"));
    }

    @Test
    void notPalindrome() {
        assertFalse(new Solution().isPalindromicAccountNumber("1234-5678"));
    }

    @Test
    void emptyAllSeparators() {
        assertTrue(new Solution().isPalindromicAccountNumber("---"));
    }

    @Test
    void caseFolding() {
        assertTrue(new Solution().isPalindromicAccountNumber("ab-BA"));
    }
}
